diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 706cb828acc6..1ac0ce4e4a1e 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -4120,6 +4120,57 @@ Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
       return BinaryOperator::CreateAnd(NotNullA, NotNullB);
     }
   }
+  // umul.with.overflow(X, C0).overflow || (result u> C1)
+  // This simplifies to X > floor(C1 / C0).
+  // Proof:
+  // - When X * C0 < 2^N (no overflow): result = X * C0, so result > C1 iff X > C1/C0.
+  // - When X * C0 >= 2^N (overflow): the overflow flag is true, so the condition is true.
+  //   Note: X >= ceil(2^N / C0) implies X > floor(C1 / C0) since C1 < 2^N.
+  // Therefore, the condition is true iff X > floor(C1 / C0).
+  Value *UMulIntr2, *UMulLHS2, *UMulRHS2;
+  const APInt *UMulC1;
+  CmpPredicate UMulPred;
+  if (match(&I, m_c_Or(
+                  m_CombineAnd(m_ExtractValue<1>(m_Value(UMulIntr2)), m_Value(Ov)),
+                  m_OneUse(m_ICmp(UMulPred, m_ExtractValue<0>(m_Deferred(UMulIntr2)),
+                                 m_APInt(UMulC1)))))) {
+    if (auto *CI = dyn_cast<CallInst>(UMulIntr2)) {
+      Function *F = CI->getCalledFunction();
+      if (F && F->getIntrinsicID() == Intrinsic::umul_with_overflow) {
+        UMulLHS2 = CI->getArgOperand(0);
+        UMulRHS2 = CI->getArgOperand(1);
+        // Handle scalar and splat vector constants
+        APInt C0Val;
+        const APInt *C0 = nullptr;
+        if (auto *C0Int = dyn_cast<ConstantInt>(UMulRHS2)) {
+          C0 = &C0Int->getValue();
+        } else if (auto *C0Vec = dyn_cast<ConstantDataVector>(UMulRHS2)) {
+          if (C0Vec->isSplat()) {
+            if (auto *C0Splat = dyn_cast<ConstantInt>(C0Vec->getSplatValue())) {
+              C0Val = C0Splat->getValue();
+              C0 = &C0Val;
+            }
+          }
+        }
+        if (C0 && UMulPred == ICmpInst::ICMP_UGT) {
+          // Compute floor(C1 / C0)
+          APInt Threshold = UMulC1->udiv(*C0);
+          Value *ThresholdConst;
+          if (UMulLHS2->getType()->isVectorTy()) {
+            ThresholdConst = ConstantVector::getSplat(
+                ElementCount::getFixed(cast<FixedVectorType>(UMulLHS2->getType())->getNumElements()),
+                ConstantInt::get(cast<FixedVectorType>(UMulLHS2->getType())->getElementType(), Threshold));
+          } else {
+            ThresholdConst = ConstantInt::get(UMulLHS2->getType(), Threshold);
+          }
+          Value *NewCmp = Builder.CreateICmpUGT(UMulLHS2, ThresholdConst);
+          return replaceInstUsesWith(I, NewCmp);
+        }
+      }
+    }
+  }
+
+

